import { useCallback } from 'react';
import { View, Text, StyleSheet, ScrollView, FlatList, RefreshControl, Pressable } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useAuth } from '@/contexts/AuthContext';
import { useCachedQuery } from '@/hooks/useCachedQuery';
import { supabase } from '@/lib/supabase';
import { LoyaltyCardMobile } from '@/components/cards/LoyaltyCardMobile';
import { OfflineBanner } from '@/components/ui/OfflineBanner';
import { SkeletonCard } from '@/components/ui/Skeleton';
import { EmptyState } from '@/components/ui/EmptyState';
import { Badge } from '@/components/ui/Badge';
import theme from '@/theme';
import type { LoyaltyCard, Reward, Scan } from '@astrolab/shared';

export default function Dashboard() {
  const router = useRouter();
  const { profile } = useAuth();

  const { data: cards, loading: cardsLoading, refresh: refreshCards } = useCachedQuery<LoyaltyCard[]>(
    'dashboard_cards',
    async () => {
      const { data, error } = await supabase
        .from('loyalty_cards')
        .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
        .order('updated_at', { ascending: false })
        .limit(10);
      if (error) throw error;
      return (data as unknown as LoyaltyCard[]) ?? [];
    },
    []
  );

  const { data: rewards, refresh: refreshRewards } = useCachedQuery<Reward[]>(
    'dashboard_rewards',
    async () => {
      const { data, error } = await supabase
        .from('rewards')
        .select('*')
        .eq('is_redeemed', false)
        .order('created_at', { ascending: false })
        .limit(5);
      if (error) throw error;
      return (data as Reward[]) ?? [];
    },
    []
  );

  const { data: recentScans, refresh: refreshScans } = useCachedQuery<Scan[]>(
    'dashboard_scans',
    async () => {
      const { data, error } = await supabase
        .from('scans')
        .select('*, merchants(name)')
        .order('created_at', { ascending: false })
        .limit(5);
      if (error) throw error;
      return (data as unknown as Scan[]) ?? [];
    },
    []
  );

  const onRefresh = useCallback(() => {
    refreshCards();
    refreshRewards();
    refreshScans();
  }, []);

  const totalCards = cards?.length ?? 0;
  const pendingRewards = rewards?.length ?? 0;
  const totalScans = recentScans?.length ?? 0;

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <OfflineBanner />
      <ScrollView
        refreshControl={<RefreshControl refreshing={false} onRefresh={onRefresh} tintColor={theme.colors.primary} />}
        contentContainerStyle={styles.scrollContent}
      >
        {/* Header */}
        <View style={styles.header}>
          <View>
            <Text style={styles.greeting}>
              Bonjour {profile?.full_name?.split(' ')[0] ?? ''} 👋
            </Text>
            <Text style={styles.subGreeting}>Votre fidelite en un coup d'oeil</Text>
          </View>
        </View>

        {/* Stats row */}
        <View style={styles.statsRow}>
          {[
            { label: 'Cartes', value: totalCards, emoji: '💳' },
            { label: 'Recompenses', value: pendingRewards, emoji: '🎁' },
            { label: 'Scans', value: totalScans, emoji: '📱' },
          ].map((stat) => (
            <View key={stat.label} style={styles.statCard}>
              <Text style={styles.statEmoji}>{stat.emoji}</Text>
              <Text style={styles.statValue}>{stat.value}</Text>
              <Text style={styles.statLabel}>{stat.label}</Text>
            </View>
          ))}
        </View>

        {/* Cards horizontal */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Text style={styles.sectionTitle}>Mes cartes</Text>
            <Pressable onPress={() => router.push('/(tabs)/cards')}>
              <Text style={styles.seeAll}>Voir tout →</Text>
            </Pressable>
          </View>
          {cardsLoading ? (
            <View style={{ flexDirection: 'row', gap: 12 }}>
              <SkeletonCard />
              <SkeletonCard />
            </View>
          ) : !cards?.length ? (
            <EmptyState
              icon="💳"
              title="Aucune carte"
              description="Scannez un QR code en magasin pour obtenir votre premiere carte."
            />
          ) : (
            <FlatList
              data={cards}
              horizontal
              showsHorizontalScrollIndicator={false}
              keyExtractor={(item) => item.id}
              contentContainerStyle={{ gap: 12 }}
              renderItem={({ item }) => (
                <Pressable onPress={() => router.push(`/(tabs)/cards/${item.id}`)}>
                  <LoyaltyCardMobile card={item} />
                </Pressable>
              )}
            />
          )}
        </View>

        {/* Pending rewards */}
        {pendingRewards > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Recompenses a recuperer 🎉</Text>
            {rewards?.map((reward) => (
              <View key={reward.id} style={styles.rewardItem}>
                <View style={{ flex: 1 }}>
                  <Text style={styles.rewardText}>{reward.description}</Text>
                  <Text style={styles.rewardDate}>
                    {new Date(reward.created_at).toLocaleDateString('fr-FR')}
                  </Text>
                </View>
                <Badge variant="success">A recuperer</Badge>
              </View>
            ))}
          </View>
        )}

        {/* Recent activity */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Activite recente</Text>
          {!recentScans?.length ? (
            <Text style={styles.emptyText}>Aucune activite recente</Text>
          ) : (
            recentScans.map((scan) => (
              <View key={scan.id} style={styles.activityItem}>
                <Text style={styles.activityEmoji}>📱</Text>
                <View style={{ flex: 1 }}>
                  <Text style={styles.activityText}>
                    {(scan as any).merchants?.name ?? 'Magasin'}
                  </Text>
                  <Text style={styles.activityDetail}>
                    {scan.stamps_added ? `+${scan.stamps_added} tampon(s)` : ''}
                    {scan.points_added ? `+${scan.points_added} pts` : ''}
                  </Text>
                </View>
                <Text style={styles.activityDate}>
                  {new Date(scan.created_at).toLocaleDateString('fr-FR')}
                </Text>
              </View>
            ))
          )}
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  scrollContent: { paddingBottom: 100 },
  header: { paddingHorizontal: theme.spacing.lg, paddingTop: theme.spacing.md, paddingBottom: theme.spacing.lg },
  greeting: { fontSize: theme.fontSize['2xl'], fontWeight: '700', color: theme.colors.text },
  subGreeting: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, marginTop: 2 },
  statsRow: { flexDirection: 'row', paddingHorizontal: theme.spacing.lg, gap: theme.spacing.sm, marginBottom: theme.spacing.lg },
  statCard: { flex: 1, backgroundColor: theme.colors.surface, borderRadius: theme.borderRadius.lg, padding: theme.spacing.md, alignItems: 'center', ...theme.shadow },
  statEmoji: { fontSize: 24, marginBottom: 4 },
  statValue: { fontSize: theme.fontSize.xl, fontWeight: '700', color: theme.colors.text },
  statLabel: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted },
  section: { paddingHorizontal: theme.spacing.lg, marginBottom: theme.spacing.lg },
  sectionHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm },
  sectionTitle: { fontSize: theme.fontSize.lg, fontWeight: '600', color: theme.colors.text },
  seeAll: { fontSize: theme.fontSize.sm, color: theme.colors.primary, fontWeight: '500' },
  rewardItem: { flexDirection: 'row', alignItems: 'center', backgroundColor: theme.colors.surface, borderRadius: theme.borderRadius.md, padding: theme.spacing.md, marginTop: theme.spacing.sm, ...theme.shadow },
  rewardText: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
  rewardDate: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted, marginTop: 2 },
  emptyText: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.lg },
  activityItem: { flexDirection: 'row', alignItems: 'center', gap: theme.spacing.sm, paddingVertical: theme.spacing.sm, borderBottomWidth: 1, borderBottomColor: theme.colors.border },
  activityEmoji: { fontSize: 20 },
  activityText: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
  activityDetail: { fontSize: theme.fontSize.xs, color: theme.colors.primary },
  activityDate: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted },
});
```

