```tsx
import { View, Text, StyleSheet, ScrollView, RefreshControl } from 'react-native';
import { useLocalSearchParams, Stack } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import QRCode from 'react-native-qrcode-svg';
import { useCachedQuery } from '@/hooks/useCachedQuery';
import { useBrightness } from '@/hooks/useBrightness';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { CircularProgress } from '@/components/cards/CircularProgress';
import { StampsGridMobile } from '@/components/cards/StampsGridMobile';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { SkeletonCard } from '@/components/ui/Skeleton';
import theme from '@/theme';
import type { LoyaltyCard, Scan, Reward } from '@astrolab/shared';

export default function CardDetailScreen() {
  const { cardId } = useLocalSearchParams<{ cardId: string }>();
  const { user } = useAuth();

  // Maximize brightness for QR display
  useBrightness(true);

  const { data: card, loading, refresh } = useCachedQuery<LoyaltyCard | null>(
    `card_${cardId}`,
    async () => {
      const { data, error } = await supabase
        .from('loyalty_cards')
        .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
        .eq('id', cardId)
        .single();
      if (error) throw error;
      return data as unknown as LoyaltyCard;
    },
    [cardId]
  );

  const { data: scans } = useCachedQuery<Scan[]>(
    `card_scans_${cardId}`,
    async () => {
      if (!card) return [];
      const { data, error } = await supabase
        .from('scans')
        .select('*')
        .eq('merchant_id', card.merchant_id)
        .order('created_at', { ascending: false })
        .limit(10);
      if (error) throw error;
      return (data as Scan[]) ?? [];
    },
    [card?.merchant_id]
  );

  const { data: rewards } = useCachedQuery<Reward[]>(
    `card_rewards_${cardId}`,
    async () => {
      if (!card) return [];
      const { data, error } = await supabase
        .from('rewards')
        .select('*')
        .eq('merchant_id', card.merchant_id)
        .order('created_at', { ascending: false })
        .limit(5);
      if (error) throw error;
      return (data as Reward[]) ?? [];
    },
    [card?.merchant_id]
  );

  const merchant = (card as any)?.merchants;
  const isStamps = card?.card_type === 'stamps' || merchant?.loyalty_type === 'stamps';
  const maxStamps = merchant?.stamps_required ?? 10;
  const currentStamps = card?.current_stamps ?? 0;
  const currentPoints = card?.current_points ?? 0;
  const rewardThreshold = merchant?.reward_threshold ?? 100;

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ headerShown: true, title: 'Chargement...' }} />
        <View style={styles.content}><SkeletonCard /><SkeletonCard /></View>
      </SafeAreaView>
    );
  }

  if (!card) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ headerShown: true, title: 'Carte introuvable' }} />
        <View style={styles.content}>
          <Text style={styles.errorText}>Cette carte n'existe pas ou a ete supprimee.</Text>
        </View>
      </SafeAreaView>
    );
  }

  // QR data for merchant to scan (customer's unique ID)
  const qrData = JSON.stringify({
    type: 'customer',
    customer_id: user?.id,
    card_id: card.id,
  });

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <Stack.Screen
        options={{
          headerShown: true,
          title: merchant?.name ?? 'Carte',
          headerStyle: { backgroundColor: theme.colors.background },
          headerTintColor: theme.colors.text,
        }}
      />
      <ScrollView
        refreshControl={<RefreshControl refreshing={false} onRefresh={refresh} tintColor={theme.colors.primary} />}
        contentContainerStyle={styles.content}
      >
        {/* Progress */}
        <Card style={styles.progressCard}>
          {isStamps ? (
            <>
              <Text style={styles.progressTitle}>
                {currentStamps}/{maxStamps} tampons
              </Text>
              <StampsGridMobile current={currentStamps} max={maxStamps} />
            </>
          ) : (
            <>
              <Text style={styles.progressTitle}>
                {currentPoints}/{rewardThreshold} points
              </Text>
              <CircularProgress
                current={currentPoints}
                max={rewardThreshold}
                size={160}
                label={`${currentPoints} pts`}
              />
            </>
          )}
        </Card>

        {/* QR Code for merchant to scan */}
        <Card style={styles.qrCard}>
          <Text style={styles.qrTitle}>Votre QR code client</Text>
          <Text style={styles.qrSubtitle}>Presentez-le au commercant</Text>
          <View style={styles.qrContainer}>
            <QRCode value={qrData} size={200} backgroundColor="#fff" color="#000" />
          </View>
        </Card>

        {/* Rewards */}
        {rewards && rewards.length > 0 && (
          <Card>
            <Text style={styles.sectionTitle}>Recompenses</Text>
            {rewards.map((r) => (
              <View key={r.id} style={styles.rewardRow}>
                <Text style={{ flex: 1, fontSize: theme.fontSize.sm, color: theme.colors.text }}>
                  {r.description}
                </Text>
                <Badge variant={r.is_redeemed ? 'neutral' : 'success'}>
                  {r.is_redeemed ? 'Utilisee' : 'Disponible'}
                </Badge>
              </View>
            ))}
          </Card>
        )}

        {/* Recent scans */}
        <Card>
          <Text style={styles.sectionTitle}>Historique des scans</Text>
          {!scans?.length ? (
            <Text style={styles.emptyText}>Aucun scan pour le moment</Text>
          ) : (
            scans.map((s) => (
              <View key={s.id} style={styles.scanRow}>
                <Text style={styles.scanDate}>
                  {new Date(s.created_at).toLocaleDateString('fr-FR')}
                </Text>
                <Text style={styles.scanDetail}>
                  {s.stamps_added ? `+${s.stamps_added} tampon(s)` : `+${s.points_added} pts`}
                </Text>
              </View>
            ))
          )}
        </Card>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  content: { padding: theme.spacing.lg, gap: theme.spacing.md, paddingBottom: 100 },
  progressCard: { alignItems: 'center', paddingVertical: theme.spacing.xl },
  progressTitle: { fontSize: theme.fontSize.lg, fontWeight: '700', color: theme.colors.text, marginBottom: theme.spacing.md },
